# tests/load/locustfile.py
import time, json
from locust import HttpUser, TaskSet, task, between, events
from locust.runners import MasterRunner

# Shared counters (thread-safe via Locust's gevent model)
_ttft_samples = []
_token_counts = []


class ChatTaskSet(TaskSet):
    """Models the /chat streaming endpoint."""

    PROMPTS = [
        "Explain transformer attention in one paragraph.",
        "What are the main causes of model hallucination?",
        "Summarize the key ideas of retrieval-augmented generation.",
        "How does temperature affect LLM output diversity?",
    ]

    @task(3)
    def chat_stream(self):
        payload = {
            "message": self.PROMPTS[int(time.time()) % len(self.PROMPTS)],
            "session_id": f"load-test-{self.user.environment.runner.user_count}",
        }
        start = time.perf_counter()
        first_token_time = None
        total_tokens = 0

        with self.client.post(
            "/chat",
            json=payload,
            stream=True,
            catch_response=True,
            timeout=60,
        ) as resp:
            if resp.status_code != 200:
                resp.failure(f"HTTP {resp.status_code}")
                return

            for line in resp.iter_lines():
                if not line:
                    continue
                if first_token_time is None:
                    first_token_time = time.perf_counter() - start
                    _ttft_samples.append(first_token_time * 1000)  # ms
                chunk = line.decode("utf-8").lstrip("data: ")
                try:
                    data = json.loads(chunk)
                    total_tokens += data.get("tokens", 1)
                except Exception:
                    pass

            resp.success()
            _token_counts.append(total_tokens)

    @task(1)
    def rag_search(self):
        """RAG path: embedding + vector search + LLM synthesis."""
        with self.client.post(
            "/search",
            json={"query": "How do I reduce hallucinations in production?"},
            catch_response=True,
            timeout=45,
        ) as resp:
            if resp.status_code == 429:
                resp.failure("Rate limited")
            elif resp.status_code != 200:
                resp.failure(f"HTTP {resp.status_code}")
            else:
                resp.success()


class GenAIUser(HttpUser):
    tasks = [ChatTaskSet]
    wait_time = between(1, 4)  # realistic think time between requests
